   130→/** @internal */
   131→async function getCompressedTokenAccountsByOwnerOrDelegate(
   132→    rpc: Rpc,
   133→    ownerOrDelegate: PublicKey,
   134→    options: GetCompressedTokenAccountsByOwnerOrDelegateOptions,
   135→    filterByDelegate: boolean = false,
   136→): Promise<WithCursor<ParsedTokenAccount[]>> {
   137→    const endpoint = filterByDelegate
   138→        ? versionedEndpoint('getCompressedTokenAccountsByDelegate')
   139→        : versionedEndpoint('getCompressedTokenAccountsByOwner');
   140→    const propertyToCheck = filterByDelegate ? 'delegate' : 'owner';
   141→
   142→    const unsafeRes = await rpcRequest(rpc.compressionApiEndpoint, endpoint, {
   143→        [propertyToCheck]: ownerOrDelegate.toBase58(),
   144→        mint: options.mint?.toBase58(),
   145→        limit: options.limit?.toNumber(),
   146→        cursor: options.cursor,
   147→    });
   148→    let res;
   149→    if (featureFlags.isV2()) {
   150→        res = create(
   151→            unsafeRes,
   152→            jsonRpcResultAndContext(
   153→                CompressedTokenAccountsByOwnerOrDelegateResultV2,
   154→            ),
   155→        );
   156→    } else {
   157→        res = create(
   158→            unsafeRes,
   159→            jsonRpcResultAndContext(
   160→                CompressedTokenAccountsByOwnerOrDelegateResult,
   161→            ),
   162→        );
   163→    }
   164→    if ('error' in res) {
   165→        throw new SolanaJSONRPCError(
   166→            res.error,
   167→            `failed to get info for compressed accounts by ${propertyToCheck} ${ownerOrDelegate.toBase58()}`,
   168→        );
   169→    }
   170→    if (res.result.value === null) {
   171→        throw new Error('not implemented: NULL result');
   172→    }
   173→    const accounts: ParsedTokenAccount[] = [];
   174→
   175→    const activeStateTreeInfos = await rpc.getStateTreeInfos();
   176→
   177→    res.result.value.items.map(item => {
   178→        const _account = item.account;
   179→        const _tokenData = item.tokenData;
   180→
   181→        const tree = featureFlags.isV2()
   182→            ? (_account as any).merkleContext.tree
   183→            : (_account as any).tree;
   184→
   185→        const proveByIndex = featureFlags.isV2()
   186→            ? (_account as any).proveByIndex
   187→            : false;
   188→        const stateTreeInfo = getStateTreeInfoByPubkey(
   189→            activeStateTreeInfos,
   190→            tree,
   191→        );
   192→
   193→        const compressedAccount: CompressedAccountWithMerkleContext =
   194→            createCompressedAccountWithMerkleContextLegacy(
   195→                createMerkleContextLegacy(
   196→                    stateTreeInfo,
   197→                    _account.hash,
   198→                    _account.leafIndex,
   199→                    proveByIndex,
   200→                ),
   201→                _account.owner,
   202→                bn(_account.lamports),
   203→                _account.data ? parseAccountData(_account.data) : undefined,
   204→                _account.address || undefined,
   205→            );
   206→
   207→        const parsed: TokenData = {
   208→            mint: _tokenData.mint,
   209→            owner: _tokenData.owner,
   210→            amount: _tokenData.amount,
   211→            delegate: _tokenData.delegate,
   212→            state: ['uninitialized', 'initialized', 'frozen'].indexOf(
   213→                _tokenData.state,
   214→            ),
   215→            tlv: null,
   216→        };
   217→
   218→        if (
   219→            parsed[propertyToCheck]?.toBase58() !== ownerOrDelegate.toBase58()
   220→        ) {
   221→            throw new Error(
   222→                `RPC returned token account with ${propertyToCheck} different from requested ${propertyToCheck}`,
   223→            );
   224→        }
   225→
   226→        accounts.push({
   227→            compressedAccount,
   228→            parsed,
   229→        });
   230→    });
   231→    /// TODO: consider custom or different sort. Most recent here.
   232→    return {
   233→        items: accounts.sort(
   234→            (a, b) =>
   235→                b.compressedAccount.leafIndex - a.compressedAccount.leafIndex,
   236→        ),
   237→        cursor: res.result.value.cursor,
   238→    };
   239→}
