   241→/**
   242→ * Establish a Compression-compatible JSON RPC connection
   243→ *
   244→ * @param endpointOrWeb3JsConnection    endpoint to the solana cluster or
   245→ *                                      Connection object
   246→ * @param compressionApiEndpoint        Endpoint to the compression server
   247→ * @param proverEndpoint                Endpoint to the prover server. defaults
   248→ *                                      to endpoint
   249→ * @param connectionConfig              Optional connection config
   250→ */
   251→export function createRpc(
   252→    endpointOrWeb3JsConnection?: string | Connection,
   253→    compressionApiEndpoint?: string,
   254→    proverEndpoint?: string,
   255→    config?: ConnectionConfig,
   256→): Rpc {
   257→    const localEndpoint = 'http://127.0.0.1:8899';
   258→    const localCompressionApiEndpoint = 'http://127.0.0.1:8784';
   259→    const localProverEndpoint = 'http://127.0.0.1:3001';
   260→
   261→    let endpoint: string;
   262→
   263→    if (!endpointOrWeb3JsConnection) {
   264→        // Local as default
   265→        endpoint = localEndpoint;
   266→        compressionApiEndpoint =
   267→            compressionApiEndpoint || localCompressionApiEndpoint;
   268→        proverEndpoint = proverEndpoint || localProverEndpoint;
   269→    } else if (typeof endpointOrWeb3JsConnection === 'string') {
   270→        endpoint = endpointOrWeb3JsConnection;
   271→        compressionApiEndpoint = compressionApiEndpoint || endpoint;
   272→        proverEndpoint = proverEndpoint || endpoint;
   273→    } else if (endpointOrWeb3JsConnection instanceof Connection) {
   274→        endpoint = endpointOrWeb3JsConnection.rpcEndpoint;
   275→        compressionApiEndpoint = compressionApiEndpoint || endpoint;
   276→        proverEndpoint = proverEndpoint || endpoint;
   277→    }
   278→    // 3
   279→    else {
   280→        throw new Error('Invalid endpoint or connection type');
   281→    }
   282→
   283→    return new Rpc(endpoint, compressionApiEndpoint, proverEndpoint, config);
   284→}
