   286→/**
   287→ * Helper function to preprocess the response to wrap numbers as strings
   288→ * @param {string} text - The JSON string to preprocess
   289→ * @returns {string} - The preprocessed JSON string with numbers wrapped as strings
   290→ */
   291→export function wrapBigNumbersAsStrings(text: string): string {
   292→    return text.replace(/(":\s*)(-?\d+)(\s*[},])/g, (match, p1, p2, p3) => {
   293→        const num = Number(p2);
   294→        if (
   295→            !Number.isNaN(num) &&
   296→            (num > Number.MAX_SAFE_INTEGER || num < Number.MIN_SAFE_INTEGER)
   297→        ) {
   298→            return `${p1}"${p2}"${p3}`;
   299→        }
   300→        return match;
   301→    });
   302→}
