   304→/** @internal */
   305→export const rpcRequest = async (
   306→    rpcEndpoint: string,
   307→    method: string,
   308→    params: any = [],
   309→    convertToCamelCase = true,
   310→    debug = false,
   311→): Promise<any> => {
   312→    const body = JSON.stringify({
   313→        jsonrpc: '2.0',
   314→        id: 'test-account',
   315→        method: method,
   316→        params: params,
   317→    });
   318→
   319→    if (debug) {
   320→        const generateCurlSnippet = () => {
   321→            const escapedBody = body.replace(/"/g, '\\"');
   322→            return `curl -X POST ${rpcEndpoint} \\
   323→     -H "Content-Type: application/json" \\
   324→     -d "${escapedBody}"`;
   325→        };
   326→
   327→        console.log('Debug: Stack trace:');
   328→        console.log(new Error().stack);
   329→        console.log('\nDebug: curl:');
   330→        console.log(generateCurlSnippet());
   331→        console.log('\n');
   332→    }
   333→
   334→    const response = await fetch(rpcEndpoint, {
   335→        method: 'POST',
   336→        headers: { 'Content-Type': 'application/json' },
   337→        body: body,
   338→    });
   339→
   340→    if (!response.ok) {
   341→        throw new Error(`HTTP error! status: ${response.status}`);
   342→    }
   343→
   344→    const text = await response.text();
   345→
   346→    const wrappedJsonString = wrapBigNumbersAsStrings(text);
   347→
   348→    if (convertToCamelCase) {
   349→        return toCamelCase(JSON.parse(wrappedJsonString));
   350→    }
   351→
   352→    return JSON.parse(wrappedJsonString);
   353→};
