   355→/** @internal */
   356→export const proverRequest = async (
   357→    proverEndpoint: string,
   358→    method: 'inclusion' | 'new-address' | 'combined',
   359→    params: any = [],
   360→    log = false,
   361→    _publicInputHash: BN | undefined = undefined, // Not supported.
   362→): Promise<ValidityProof> => {
   363→    let logMsg: string = '';
   364→
   365→    if (log) {
   366→        logMsg = `Proof generation for method:${method}`;
   367→        console.time(logMsg);
   368→    }
   369→
   370→    let body;
   371→    if (method === 'inclusion') {
   372→        body = JSON.stringify({
   373→            circuitType: 'inclusion',
   374→            stateTreeHeight: 26,
   375→            inputCompressedAccounts: params,
   376→        });
   377→    } else if (method === 'new-address') {
   378→        body = JSON.stringify({
   379→            circuitType: 'non-inclusion',
   380→            addressTreeHeight: 26,
   381→            newAddresses: params,
   382→        });
   383→    } else if (method === 'combined') {
   384→        body = JSON.stringify({
   385→            circuitType: 'combined',
   386→
   387→            stateTreeHeight: 26,
   388→            addressTreeHeight: 26,
   389→            inputCompressedAccounts: params[0],
   390→            newAddresses: params[1],
   391→        });
   392→    }
   393→
   394→    const response = await fetch(`${proverEndpoint}/prove`, {
   395→        method: 'POST',
   396→        headers: { 'Content-Type': 'application/json' },
   397→        body: body,
   398→    });
   399→
   400→    if (!response.ok) {
   401→        throw new Error(`Error fetching proof: ${response.statusText}`);
   402→    }
   403→    const data: any = await response.json();
   404→    const parsed = proofFromJsonStruct(data);
   405→    const compressedProof = negateAndCompressProof(parsed);
   406→
   407→    if (log) console.timeEnd(logMsg);
   408→
   409→    return compressedProof;
   410→};
