   444→export function convertMerkleProofsWithContextToHex(
   445→    merkleProofsWithContext: MerkleContextWithMerkleProof[],
   446→): HexInputsForProver[] {
   447→    const inputs: HexInputsForProver[] = [];
   448→
   449→    for (let i = 0; i < merkleProofsWithContext.length; i++) {
   450→        const input: HexInputsForProver = {
   451→            root: toHex(merkleProofsWithContext[i].root),
   452→            pathIndex: merkleProofsWithContext[i].leafIndex,
   453→            pathElements: merkleProofsWithContext[i].merkleProof.map(hex =>
   454→                toHex(hex),
   455→            ),
   456→            leaf: toHex(bn(merkleProofsWithContext[i].hash)),
   457→        };
   458→        inputs.push(input);
   459→    }
   460→
   461→    return inputs;
   462→}
   463→
   464→export function convertNonInclusionMerkleProofInputsToHex(
   465→    nonInclusionMerkleProofInputs: MerkleContextWithNewAddressProof[],
   466→): NonInclusionJsonStruct[] {
   467→    const inputs: NonInclusionJsonStruct[] = [];
   468→    for (let i = 0; i < nonInclusionMerkleProofInputs.length; i++) {
   469→        const input: NonInclusionJsonStruct = {
   470→            root: toHex(nonInclusionMerkleProofInputs[i].root),
   471→            value: toHex(nonInclusionMerkleProofInputs[i].value),
   472→            pathIndex:
   473→                nonInclusionMerkleProofInputs[
   474→                    i
   475→                ].indexHashedIndexedElementLeaf.toNumber(),
   476→            pathElements: nonInclusionMerkleProofInputs[
   477→                i
   478→            ].merkleProofHashedIndexedElementLeaf.map(hex => toHex(hex)),
   479→            nextIndex: nonInclusionMerkleProofInputs[i].nextIndex.toNumber(),
   480→            leafLowerRangeValue: toHex(
   481→                nonInclusionMerkleProofInputs[i].leafLowerRangeValue,
   482→            ),
   483→            leafHigherRangeValue: toHex(
   484→                nonInclusionMerkleProofInputs[i].leafHigherRangeValue,
   485→            ),
   486→        };
   487→        inputs.push(input);
   488→    }
   489→    return inputs;
   490→}
