   492→function calculateTwoInputsHashChain(
   493→    hashesFirst: BN[],
   494→    hashesSecond: BN[],
   495→    lightWasm: LightWasm,
   496→): BN {
   497→    if (hashesFirst.length !== hashesSecond.length) {
   498→        throw new Error('Input lengths must match.');
   499→    }
   500→    if (hashesFirst.length === 0) {
   501→        return bn(0);
   502→    }
   503→
   504→    let hashChain = lightWasm.poseidonHashBN([
   505→        hashesFirst[0].toString(),
   506→        hashesSecond[0].toString(),
   507→    ]);
   508→
   509→    for (let i = 1; i < hashesFirst.length; i++) {
   510→        hashChain = lightWasm.poseidonHashBN([
   511→            hashChain.toString(),
   512→            hashesFirst[i].toString(),
   513→            hashesSecond[i].toString(),
   514→        ]);
   515→    }
   516→
   517→    return hashChain;
   518→}
   519→
   520→export function getPublicInputHash(
   521→    accountProofs: MerkleContextWithMerkleProof[],
   522→    accountHashes: BN254[],
   523→    newAddressProofs: MerkleContextWithNewAddressProof[],
   524→    lightWasm: LightWasm,
   525→): BN {
   526→    const accountRoots = accountProofs.map(x => x.root);
   527→    const inclusionHashChain = calculateTwoInputsHashChain(
   528→        accountRoots,
   529→        accountHashes,
   530→        lightWasm,
   531→    );
   532→
   533→    const newAddressHashes = newAddressProofs.map(x => x.value);
   534→    const newAddressRoots = newAddressProofs.map(x => x.root);
   535→    const nonInclusionHashChain = calculateTwoInputsHashChain(
   536→        newAddressRoots,
   537→        newAddressHashes,
   538→        lightWasm,
   539→    );
   540→
   541→    if (!nonInclusionHashChain.isZero()) {
   542→        return nonInclusionHashChain;
   543→    } else if (!inclusionHashChain.isZero()) {
   544→        return inclusionHashChain;
   545→    } else {
   546→        return calculateTwoInputsHashChain(
   547→            [inclusionHashChain],
   548→            [nonInclusionHashChain],
   549→            lightWasm,
   550→        );
   551→    }
   552→}
