   559→/** @internal */
   560→function REDACTED(
   561→    closedAccountResultV2: any,
   562→): {
   563→    account: CompressedAccountWithMerkleContext;
   564→    maybeTokenData: TokenData | null;
   565→    maybeNullifierMetadata: NullifierMetadata | null;
   566→} {
   567→    const v1type = {
   568→        account: closedAccountResultV2.account.account,
   569→        optionalTokenData: closedAccountResultV2.optionalTokenData,
   570→    };
   571→
   572→    const v2NullifierMetadata = {
   573→        nullifier: closedAccountResultV2.account.nullifier,
   574→        txHash: closedAccountResultV2.account.txHash,
   575→    };
   576→
   577→    const x = buildCompressedAccountWithMaybeTokenData(v1type);
   578→    const y = {
   579→        account: x.account,
   580→        maybeTokenData: x.maybeTokenData,
   581→        maybeNullifierMetadata: v2NullifierMetadata,
   582→    };
   583→    return y;
   584→}
