   586→/** @internal */
   587→function buildCompressedAccountWithMaybeTokenData(
   588→    accountStructWithOptionalTokenData: any,
   589→): {
   590→    account: CompressedAccountWithMerkleContext;
   591→    maybeTokenData: TokenData | null;
   592→} {
   593→    const compressedAccountResult = accountStructWithOptionalTokenData.account;
   594→    const tokenDataResult =
   595→        accountStructWithOptionalTokenData.optionalTokenData;
   596→
   597→    const compressedAccount: CompressedAccountWithMerkleContext =
   598→        createCompressedAccountWithMerkleContextLegacy(
   599→            createMerkleContextLegacy(
   600→                compressedAccountResult.treeInfo,
   601→                compressedAccountResult.hash.toArray('be', 32),
   602→                compressedAccountResult.leafIndex,
   603→                compressedAccountResult.proveByIndex,
   604→            ),
   605→            compressedAccountResult.owner,
   606→            bn(compressedAccountResult.lamports),
   607→            compressedAccountResult.data
   608→                ? parseAccountData(compressedAccountResult.data)
   609→                : undefined,
   610→            compressedAccountResult.address || undefined,
   611→        );
   612→
   613→    if (tokenDataResult === null) {
   614→        return { account: compressedAccount, maybeTokenData: null };
   615→    }
   616→
   617→    const parsed: TokenData = {
   618→        mint: tokenDataResult.mint,
   619→        owner: tokenDataResult.owner,
   620→        amount: tokenDataResult.amount,
   621→        delegate: tokenDataResult.delegate,
   622→        state: ['uninitialized', 'initialized', 'frozen'].indexOf(
   623→            tokenDataResult.state,
   624→        ),
   625→        tlv: null,
   626→    };
   627→
   628→    return { account: compressedAccount, maybeTokenData: parsed };
   629→}
   630→/**
   631→ * Merge signatures from Solana RPC and compression indexer.
   632→ * Deduplicates by signature, tracking sources in the `sources` array.
   633→ * When a signature exists in both, uses Solana data (richer) but marks both sources.
   634→ */
   635→export function mergeSignatures(
   636→    solanaSignatures: ConfirmedSignatureInfo[],
   637→    compressedSignatures: SignatureWithMetadata[],
   638→): UnifiedSignatureInfo[] {
   639→    const signatureMap = new Map<string, UnifiedSignatureInfo>();
   640→
   641→    // Process compressed signatures first
   642→    for (const sig of compressedSignatures) {
   643→        signatureMap.set(sig.signature, {
   644→            signature: sig.signature,
   645→            slot: sig.slot,
   646→            blockTime: sig.blockTime,
   647→            err: null,
   648→            memo: null,
   649→            confirmationStatus: undefined,
   650→            sources: [SignatureSource.Compressed],
   651→        });
   652→    }
   653→
   654→    // Process Solana signatures, merging sources if duplicate
   655→    for (const sig of solanaSignatures) {
   656→        const existing = signatureMap.get(sig.signature);
   657→        if (existing) {
   658→            // Found in both - use Solana data (richer), add both sources
   659→            signatureMap.set(sig.signature, {
   660→                signature: sig.signature,
   661→                slot: sig.slot,
   662→                blockTime: sig.blockTime ?? null,
   663→                err: sig.err,
   664→                memo: sig.memo ?? null,
   665→                confirmationStatus: sig.confirmationStatus,
   666→                sources: [SignatureSource.Solana, SignatureSource.Compressed],
   667→            });
   668→        } else {
   669→            // Only in Solana
   670→            signatureMap.set(sig.signature, {
   671→                signature: sig.signature,
   672→                slot: sig.slot,
   673→                blockTime: sig.blockTime ?? null,
   674→                err: sig.err,
   675→                memo: sig.memo ?? null,
   676→                confirmationStatus: sig.confirmationStatus,
   677→                sources: [SignatureSource.Solana],
   678→            });
   679→        }
   680→    }
   681→
   682→    // Sort by slot descending (most recent first)
   683→    return Array.from(signatureMap.values()).sort((a, b) => b.slot - a.slot);
   684→}
