   686→/**
   687→ *
   688→ */
   689→export class Rpc extends Connection implements CompressionApiInterface {
   690→    compressionApiEndpoint: string;
   691→    proverEndpoint: string;
   692→    allStateTreeInfos: TreeInfo[] | null = null;
   693→    lastStateTreeFetchTime: number | null = null;
   694→    CACHE_TTL = 1000 * 60 * 60; // 1 hour in ms
   695→    fetchPromise: Promise<TreeInfo[]> | null = null;
   696→
   697→    constructor(
   698→        endpoint: string,
   699→        compressionApiEndpoint: string,
   700→        proverEndpoint: string,
   701→        config?: ConnectionConfig,
   702→    ) {
   703→        super(endpoint, config || 'confirmed');
   704→        this.compressionApiEndpoint = compressionApiEndpoint;
   705→        this.proverEndpoint = proverEndpoint;
   706→    }
   707→    /**
   708→     * @deprecated Use {@link getStateTreeInfos} instead
   709→     */
   710→    async getCachedActiveStateTreeInfo() {}
   711→    /**
   712→     * @deprecated Use {@link getStateTreeInfos} instead
   713→     */
   714→    async getCachedActiveStateTreeInfos() {}
   715→
   716→    /**
   717→     * Get a list of all state tree infos. If not already cached, fetches from
   718→     * the cluster.
   719→     * if featureFlags.isV2(), returns v2 trees too.
   720→     */
   721→    async getStateTreeInfos(): Promise<TreeInfo[]> {
   722→        if (isLocalTest(this.rpcEndpoint)) {
   723→            return localTestActiveStateTreeInfos();
   724→        }
   725→
   726→        // return cached
   727→        if (this.allStateTreeInfos && this.lastStateTreeFetchTime) {
   728→            const now = Date.now();
   729→            if (now - this.lastStateTreeFetchTime <= this.CACHE_TTL) {
   730→                return this.allStateTreeInfos;
   731→            }
   732→        }
   733→
   734→        if (this.fetchPromise) {
   735→            return this.fetchPromise;
   736→        }
   737→
   738→        let info: TreeInfo[] | undefined;
   739→        try {
   740→            this.fetchPromise = this.doFetch();
   741→            info = await this.fetchPromise;
   742→            this.allStateTreeInfos = info;
   743→            this.lastStateTreeFetchTime = Date.now();
   744→            return info;
   745→        } finally {
   746→            this.fetchPromise = null;
   747→        }
   748→    }
   749→
   750→    /**
   751→     * @internal
   752→     */
   753→    async doFetch(): Promise<TreeInfo[]> {
   754→        const { mainnet, devnet } = defaultStateTreeLookupTables();
   755→
   756→        /// Mainnet keys are not available on devnet and vice versa. Chaining
   757→        /// the requests lets us get the state tree infos from the correct
   758→        /// network.
   759→        try {
   760→            const res = await getAllStateTreeInfos({
   761→                connection: this,
   762→                stateTreeLUTPairs: [mainnet[0]],
   763→            });
   764→            return res;
   765→        } catch (mainnetError) {
   766→            try {
   767→                const res = await getAllStateTreeInfos({
   768→                    connection: this,
   769→                    stateTreeLUTPairs: [devnet[0]],
   770→                });
   771→                return res;
   772→            } catch (devnetError) {
   773→                throw new Error(
   774→                    `Failed to fetch state tree infos from both mainnet and devnet. ` +
   775→                        `Mainnet error: ${mainnetError}. Devnet error: ${devnetError}`,
   776→                );
   777→            }
   778→        }
   779→    }
   780→
   781→    /**
