  1662→    /**
  1663→     * Ensure that the Compression Indexer has already indexed the transaction
  1664→     */
  1665→    async confirmTransactionIndexed(slot: number): Promise<boolean> {
  1666→        const timeout = isLocalTest(this.rpcEndpoint) ? 10000 : 20000;
  1667→        const interval = isLocalTest(this.rpcEndpoint) ? 100 : 200;
  1668→        const startTime = Date.now();
  1669→        while (true) {
  1670→            const indexerSlot = await this.getIndexerSlot();
  1671→
  1672→            if (indexerSlot >= slot) {
  1673→                return true;
  1674→            }
  1675→            if (Date.now() - startTime > timeout) {
  1676→                throw new Error(
  1677→                    `Timeout: Indexer slot did not reach the required slot within ${timeout / 1000}s`,
  1678→                );
  1679→            }
  1680→            await new Promise(resolve => setTimeout(resolve, interval));
  1681→        }
  1682→    }
