  1824→                treeInfo: {
  1825→                    tree: proof.merkleTree,
  1826→                    queue: defaultTestStateTreeAccounts().addressQueue,
  1827→                    treeType: TreeType.AddressV1,
  1828→                    nextTreeInfo: null,
