  1854→        newAddresses: BN254[] = [],
  1855→    ): Promise<ValidityProofWithContext> {
  1856→        const accs = await this.getMultipleCompressedAccounts(hashes);
  1857→        const trees = accs.map(acc => acc.treeInfo.tree);
  1858→        const queues = accs.map(acc => acc.treeInfo.queue);
  1859→
