  1869→                queue: queues[index],
  1870→            };
  1871→        });
  1872→
  1873→        const formattedNewAddresses = newAddresses.map(item => {
  1874→            return {
  1875→                address: item,
  1876→                tree: defaultAddressTreePublicKey,
  1877→                queue: defaultAddressQueuePublicKey,
  1878→            };
  1879→        });
