   280→ */
   281→const PublicKeyFromString = coerce(
   282→    instance(PublicKey),
   283→    string(),
   284→    value => new PublicKey(value),
   285→);
   286→
   287→/**
   288→ * @internal
   289→ */
   290→const ArrayFromString = coerce(instance(Array<number>), string(), value =>
   291→    Array.from(new PublicKey(value).toBytes()),
   292→);
   293→
   294→/**
   295→ * @internal
   296→ */
   297→const BN254FromString = coerce(instance(BN), string(), value => {
   298→    return createBN254(value, 'base58');
   299→});
   300→
   301→/**
   302→ * @internal
   303→ * Coerce number (0/1) or boolean to boolean
   304→ */
   305→const BooleanFromNumberOrBoolean = coerce(
   306→    boolean(),
   307→    union([number(), boolean()]),
   308→    value => Boolean(value),
   309→);
   310→
   311→/**
   312→ *
   313→ * @internal
   314→ * expects bigints to be supplied as strings.
   315→ */
   316→const BNFromStringOrNumber = coerce(
   317→    instance(BN),
   318→    union([string(), number()]),
   319→    value => {
   320→        if (typeof value === 'number') {
   321→            if (!Number.isSafeInteger(value)) {
   322→                throw new Error(`Unsafe integer. Precision loss: ${value}`);
   323→            }
   324→            return bn(value); // Safe number → BN
   325→        }
   326→        return bn(value, 10); // String → BN
   327→    },
   328→);
