   335→/**
   336→ * @internal
   337→ */
   338→export function createRpcResult<T, U>(result: Struct<T, U>) {
   339→    return union([
   340→        pick({
   341→            jsonrpc: literal('2.0'),
   342→            id: string(),
   343→            result,
   344→        }),
   345→        pick({
   346→            jsonrpc: literal('2.0'),
   347→            id: string(),
   348→            error: pick({
   349→                code: unknown(),
   350→                message: string(),
   351→                data: nullable(any()),
   352→            }),
   353→        }),
   354→    ]) as Struct<RpcResult<T>, null>;
   355→}
   356→
   357→/**
   358→ * @internal
   359→ */
   360→const UnknownRpcResult = createRpcResult(unknown());
   361→
   362→/**
   363→ * @internal
   364→ */
   365→export function jsonRpcResult<T, U>(schema: Struct<T, U>) {
   366→    return coerce(createRpcResult(schema), UnknownRpcResult, value => {
   367→        if ('error' in value) {
   368→            return value as RpcResultError;
   369→        } else {
   370→            return {
   371→                ...value,
   372→                result: create(value.result, schema),
   373→            } as RpcResultSuccess<T>;
   374→        }
   375→    }) as Struct<RpcResult<T>, null>;
   376→}
