   378→// Add this type for the context wrapper
   379→export type WithRpcContext<T> = {
   380→    context: {
   381→        slot: number;
   382→    };
   383→    value: T;
   384→};
   385→
   386→/**
   387→ * @internal
   388→ */
   389→export function jsonRpcResultAndContext<T, U>(value: Struct<T, U>) {
   390→    return jsonRpcResult(
   391→        pick({
   392→            context: pick({
   393→                slot: number(),
   394→            }),
   395→            value,
   396→        }),
   397→    ) as Struct<RpcResult<WithRpcContext<T>>, null>;
   398→}
