   275→    async getMultipleCompressedAccountProofs(
   276→        hashes: BN254[],
   277→    ): Promise<MerkleContextWithMerkleProof[]> {
   278→        // Parse events and organize leaves by their respective merkle trees
   279→        const events: PublicTransactionEvent[] = await getParsedEvents(
   280→            this,
   281→        ).then(events => events.reverse());
   282→        const leavesByTree: Map<
   283→            string,
   284→            {
   285→                leaves: number[][];
   286→                leafIndices: number[];
   287→                treeInfo: TreeInfo;
   288→            }
   289→        > = new Map();
   290→
   291→        const cachedStateTreeInfos = await this.getStateTreeInfos();
   292→
   293→        /// Assign leaves to their respective trees
   294→        for (const event of events) {
   295→            for (
   296→                let index = 0;
   297→                index < event.outputCompressedAccounts.length;
   298→                index++
   299→            ) {
   300→                const hash = event.outputCompressedAccountHashes[index];
   301→                const treeOrQueue =
   302→                    event.pubkeyArray[
   303→                        event.outputCompressedAccounts[index].merkleTreeIndex
   304→                    ];
   305→
   306→                const stateTreeInfo = getStateTreeInfoByPubkey(
   307→                    cachedStateTreeInfos,
   308→                    treeOrQueue,
   309→                );
   310→
   311→                if (!leavesByTree.has(stateTreeInfo.tree.toBase58())) {
   312→                    leavesByTree.set(stateTreeInfo.tree.toBase58(), {
   313→                        leaves: [],
   314→                        leafIndices: [],
   315→                        treeInfo: stateTreeInfo,
   316→                    });
   317→                }
   318→
   319→                const treeData = leavesByTree.get(
   320→                    stateTreeInfo.tree.toBase58(),
   321→                );
   322→                if (!treeData) {
   323→                    throw new Error(
   324→                        `Tree not found: ${stateTreeInfo.tree.toBase58()}`,
   325→                    );
   326→                }
   327→                treeData.leaves.push(hash);
   328→                treeData.leafIndices.push(event.outputLeafIndices[index]);
   329→            }
   330→        }
   331→
   332→        const merkleProofsMap: Map<string, MerkleContextWithMerkleProof> =
   333→            new Map();
   334→
   335→        for (const [treeKey, { leaves, treeInfo }] of leavesByTree.entries()) {
   336→            const tree = new PublicKey(treeKey);
   337→
   338→            let merkleTree: MerkleTree | undefined;
   339→            if (treeInfo.treeType === TreeType.StateV1) {
   340→                merkleTree = new MerkleTree(
   341→                    this.depth,
   342→                    this.lightWasm,
   343→                    leaves.map(leaf => bn(leaf).toString()),
   344→                );
   345→            } else if (treeInfo.treeType === TreeType.StateV2) {
   346→                /// In V2 State trees, The Merkle tree stays empty until the
   347→                /// first forester transaction. And since test-rpc is only used
   348→                /// for non-forested tests, we must return a tree with
   349→                /// zerovalues.
   350→                merkleTree = new MerkleTree(32, this.lightWasm, []);
   351→            } else {
   352→                throw new Error(
   353→                    `Invalid tree type: ${treeInfo.treeType} in test-rpc.ts`,
   354→                );
   355→            }
   356→
   357→            for (let i = 0; i < hashes.length; i++) {
   358→                const leafIndex = leaves.findIndex(leaf =>
   359→                    bn(leaf).eq(hashes[i]),
   360→                );
   361→
   362→                /// If leaf is part of current tree, return proof
   363→                if (leafIndex !== -1) {
   364→                    if (treeInfo.treeType === TreeType.StateV1) {
   365→                        const pathElements =
   366→                            merkleTree.path(leafIndex).pathElements;
   367→                        const bnPathElements = pathElements.map(value =>
   368→                            bn(value),
   369→                        );
   370→                        const root = bn(merkleTree.root());
   371→
   372→                        const merkleProof: MerkleContextWithMerkleProof = {
   373→                            hash: bn(hashes[i].toArray('be', 32)),
   374→                            treeInfo,
   375→                            leafIndex,
   376→                            merkleProof: bnPathElements,
   377→                            proveByIndex: false,
   378→                            rootIndex: leaves.length,
   379→                            root,
   380→                        };
   381→
   382→                        merkleProofsMap.set(hashes[i].toString(), merkleProof);
   383→                    } else if (treeInfo.treeType === TreeType.StateV2) {
   384→                        const pathElements = merkleTree._zeros.slice(0, -1);
   385→                        const bnPathElements = pathElements.map(value =>
   386→                            bn(value),
   387→                        );
   388→                        const root = bn(merkleTree.root());
   389→
   390→                        /// get leafIndex from leavesByTree for the given hash
   391→                        const leafIndex = leavesByTree
   392→                            .get(tree.toBase58())!
   393→                            .leafIndices.findIndex(index =>
   394→                                hashes[i].eq(
   395→                                    bn(
   396→                                        leavesByTree.get(tree.toBase58())!
   397→                                            .leaves[index],
   398→                                    ),
   399→                                ),
   400→                            );
   401→
   402→                        const merkleProof: MerkleContextWithMerkleProof = {
   403→                            // Hash is 0 for proveByIndex trees in test-rpc.
   404→                            hash: bn(hashes[i].toArray('be', 32)),
   405→                            // hash: bn(new Array(32).fill(0)),
   406→                            treeInfo,
   407→                            leafIndex,
   408→                            merkleProof: bnPathElements,
   409→                            proveByIndex: true,
   410→                            // Root index is 0 for proveByIndex trees in
   411→                            // test-rpc.
   412→                            rootIndex: 0,
   413→                            root,
   414→                        };
   415→
   416→                        merkleProofsMap.set(hashes[i].toString(), merkleProof);
   417→                    }
   418→                }
   419→            }
   420→        }
   421→
   422→        // Validate proofs
   423→        merkleProofsMap.forEach((proof, index) => {
   424→            if (proof.treeInfo.treeType === TreeType.StateV1) {
   425→                const leafIndex = proof.leafIndex;
   426→                const computedHash = leavesByTree.get(
   427→                    proof.treeInfo.tree.toBase58(),
   428→                )!.leaves[leafIndex];
   429→                const hashArr = bn(computedHash);
   430→                if (!hashArr.eq(proof.hash)) {
   431→                    throw new Error(
   432→                        `Mismatch at index ${index}: expected ${proof.hash.toString()}, got ${hashArr.toString()}`,
   433→                    );
   434→                }
   435→            }
   436→        });
   437→
   438→        // Ensure all requested hashes belong to the same tree type
   439→        const uniqueTreeTypes = new Set(
   440→            hashes.map(hash => {
   441→                const proof = merkleProofsMap.get(hash.toString());
   442→                if (!proof) {
   443→                    throw new Error(
   444→                        `Proof not found for hash: ${hash.toString()}`,
   445→                    );
   446→                }
   447→                return proof.treeInfo.treeType;
   448→            }),
   449→        );
   450→
   451→        if (uniqueTreeTypes.size > 1) {
   452→            throw new Error(
   453→                'Requested hashes belong to different tree types (V1/V2)',
   454→            );
   455→        }
   456→
   457→        // Return proofs in the order of requested hashes
   458→        return hashes.map(hash => {
   459→            const proof = merkleProofsMap.get(hash.toString());
   460→            if (!proof) {
   461→                throw new Error(`No proof found for hash: ${hash.toString()}`);
   462→            }
   463→            return proof;
   464→        });
   465→    }
