   670→    /**
   671→     * Fetch the latest address proofs for new unique addresses specified by an
   672→     * array of addresses.
   673→     *
   674→     * the proof states that said address have not yet been created in respective address tree.
   675→     * @param addresses Array of BN254 new addresses
   676→     * @returns Array of validity proofs for new addresses
   677→     */
   678→    async getMultipleNewAddressProofs(addresses: BN254[]) {
   679→        /// Build tree
   680→        const indexedArray = IndexedArray.default();
   681→        const allAddresses: BN[] = [];
   682→        indexedArray.init();
   683→        const hashes: BN[] = [];
   684→        // TODO(crank): add support for cranked address tree in 'allAddresses'.
   685→        // The Merkle tree root doesnt actually advance beyond init() unless we
   686→        // start emptying the address queue.
   687→        for (let i = 0; i < allAddresses.length; i++) {
   688→            indexedArray.append(bn(allAddresses[i]));
   689→        }
   690→        for (let i = 0; i < indexedArray.elements.length; i++) {
   691→            const hash = indexedArray.hashElement(this.lightWasm, i);
   692→            hashes.push(bn(hash!));
   693→        }
   694→        const tree = new MerkleTree(
   695→            this.depth,
   696→            this.lightWasm,
   697→            hashes.map(hash => bn(hash).toString()),
   698→        );
   699→
   700→        /// Creates proof for each address
   701→        const newAddressProofs: MerkleContextWithNewAddressProof[] = [];
   702→
   703→        for (let i = 0; i < addresses.length; i++) {
   704→            const [lowElement] = indexedArray.findLowElement(addresses[i]);
   705→            if (!lowElement) throw new Error('Address not found');
   706→
   707→            const leafIndex = lowElement.index;
   708→
   709→            const pathElements: string[] = tree.path(leafIndex).pathElements;
   710→            const bnPathElements = pathElements.map(value => bn(value));
   711→
   712→            const higherRangeValue = indexedArray.get(
   713→                lowElement.nextIndex,
   714→            )!.value;
   715→            const root = bn(tree.root());
   716→
   717→            const proof: MerkleContextWithNewAddressProof = {
   718→                root,
   719→                rootIndex: 3,
   720→                value: addresses[i],
   721→                leafLowerRangeValue: lowElement.value,
   722→                leafHigherRangeValue: higherRangeValue,
   723→                nextIndex: bn(lowElement.nextIndex),
   724→                merkleProofHashedIndexedElementLeaf: bnPathElements,
   725→                indexHashedIndexedElementLeaf: bn(lowElement.index),
   726→                treeInfo: {
   727→                    tree: defaultTestStateTreeAccounts().addressTree,
   728→                    queue: defaultTestStateTreeAccounts().addressQueue,
   729→                    treeType: TreeType.AddressV1,
   730→                    nextTreeInfo: null,
   731→                },
   732→            };
   733→            newAddressProofs.push(proof);
   734→        }
   735→        return newAddressProofs;
   736→    }
