   763→    /**
   764→     * Fetch the latest validity proof for (1) compressed accounts specified by
   765→     * an array of account hashes. (2) new unique addresses specified by an
   766→     * array of addresses.
   767→     *
   768→     * Validity proofs prove the presence of compressed accounts in state trees
   769→     * and the non-existence of addresses in address trees, respectively. They
   770→     * enable verification without recomputing the merkle proof path, thus
   771→     * lowering verification and data costs.
   772→     *
   773→     * @param hashes        Array of BN254 hashes.
   774→     * @param newAddresses  Array of BN254 new addresses.
   775→     * @returns             validity proof with context
   776→     */
   777→    async getValidityProof(
   778→        hashes: BN254[] = [],
   779→        newAddresses: BN254[] = [],
   780→    ): Promise<ValidityProofWithContext> {
   781→        if (newAddresses.some(address => !(address instanceof BN))) {
   782→            throw new Error('AddressWithTree is not supported in test-rpc');
   783→        }
   784→        let validityProof: ValidityProofWithContext | null;
   785→
   786→        const treeInfosUsed: TreeInfo[] = [];
   787→
   788→        if (hashes.length === 0 && newAddresses.length === 0) {
   789→            throw new Error(
   790→                'Empty input. Provide hashes and/or new addresses.',
   791→            );
   792→        } else if (hashes.length > 0 && newAddresses.length === 0) {
   793→            for (const hash of hashes) {
   794→                const account = await this.getCompressedAccount(
   795→                    undefined,
   796→                    hash,
   797→                );
   798→
   799→                if (account) {
   800→                    treeInfosUsed.push(account.treeInfo);
   801→                } else throw new Error('Account not found');
   802→            }
   803→            const hasV1Accounts = treeInfosUsed.some(
   804→                info => info.treeType === TreeType.StateV1,
   805→            );
   806→
   807→            /// inclusion
   808→            const merkleProofsWithContext =
   809→                await this.getMultipleCompressedAccountProofs(hashes);
   810→            if (hasV1Accounts) {
   811→                const inputs = convertMerkleProofsWithContextToHex(
   812→                    merkleProofsWithContext,
   813→                );
   814→
   815→                const compressedProof = await proverRequest(
   816→                    this.proverEndpoint,
   817→                    'inclusion',
   818→                    inputs,
   819→                    this.log,
   820→                );
   821→                validityProof = {
   822→                    compressedProof,
   823→                    roots: merkleProofsWithContext.map(proof => proof.root),
   824→                    rootIndices: merkleProofsWithContext.map(
   825→                        proof => proof.rootIndex,
   826→                    ),
   827→                    leafIndices: merkleProofsWithContext.map(
   828→                        proof => proof.leafIndex,
   829→                    ),
   830→                    leaves: merkleProofsWithContext.map(proof =>
   831→                        bn(proof.hash),
   832→                    ),
   833→                    treeInfos: merkleProofsWithContext.map(
   834→                        proof => proof.treeInfo,
   835→                    ),
   836→                    proveByIndices: merkleProofsWithContext.map(
   837→                        proof => proof.proveByIndex,
   838→                    ),
   839→                };
   840→            } else {
   841→                validityProof = {
   842→                    compressedProof: null,
   843→                    roots: merkleProofsWithContext.map(_proof => bn(0)),
   844→                    rootIndices: merkleProofsWithContext.map(
   845→                        proof => proof.rootIndex,
   846→                    ),
   847→                    leafIndices: merkleProofsWithContext.map(
   848→                        proof => proof.leafIndex,
   849→                    ),
   850→                    leaves: merkleProofsWithContext.map(proof =>
   851→                        bn(proof.hash),
   852→                    ),
   853→                    treeInfos: merkleProofsWithContext.map(
   854→                        proof => proof.treeInfo,
   855→                    ),
   856→                    proveByIndices: merkleProofsWithContext.map(
   857→                        proof => proof.proveByIndex,
   858→                    ),
   859→                };
   860→            }
   861→        } else if (hashes.length === 0 && newAddresses.length > 0) {
   862→            /// new-address
   863→            const newAddressProofs: MerkleContextWithNewAddressProof[] =
   864→                await this.getMultipleNewAddressProofs(newAddresses);
   865→
   866→            const inputs =
   867→                convertNonInclusionMerkleProofInputsToHex(newAddressProofs);
   868→
   869→            const compressedProof = await proverRequest(
   870→                this.proverEndpoint,
   871→                'new-address',
   872→                inputs,
   873→                this.log,
   874→            );
   875→
   876→            validityProof = {
   877→                compressedProof,
   878→                roots: newAddressProofs.map(proof => proof.root),
   879→                rootIndices: newAddressProofs.map(_ => 3),
   880→                leafIndices: newAddressProofs.map(proof =>
   881→                    proof.indexHashedIndexedElementLeaf.toNumber(),
   882→                ),
   883→                leaves: newAddressProofs.map(proof => bn(proof.value)),
   884→                treeInfos: newAddressProofs.map(proof => proof.treeInfo),
   885→                proveByIndices: newAddressProofs.map(_ => false),
   886→            };
   887→        } else if (hashes.length > 0 && newAddresses.length > 0) {
   888→            /// combined
   889→            const merkleProofsWithContext =
   890→                await this.getMultipleCompressedAccountProofs(hashes);
   891→            const newAddressProofs: MerkleContextWithNewAddressProof[] =
   892→                await this.getMultipleNewAddressProofs(newAddresses);
   893→
   894→            const treeInfosUsed = merkleProofsWithContext.map(
   895→                proof => proof.treeInfo,
   896→            );
   897→            const hasV1Accounts = treeInfosUsed.some(
   898→                info => info.treeType === TreeType.StateV1,
   899→            );
   900→
   901→            const newAddressInputs =
   902→                convertNonInclusionMerkleProofInputsToHex(newAddressProofs);
   903→
   904→            let compressedProof;
   905→            if (hasV1Accounts) {
   906→                const inputs = convertMerkleProofsWithContextToHex(
   907→                    merkleProofsWithContext,
   908→                );
   909→
   910→                compressedProof = await proverRequest(
   911→                    this.proverEndpoint,
   912→                    'combined',
   913→                    [inputs, newAddressInputs],
   914→                    true,
   915→                );
   916→            } else {
   917→                // Still need to make the prover request for new addresses
   918→                compressedProof = await proverRequest(
   919→                    this.proverEndpoint,
   920→                    'new-address',
   921→                    newAddressInputs,
   922→                    true,
   923→                );
   924→            }
   925→
   926→            validityProof = {
   927→                compressedProof,
   928→                roots: merkleProofsWithContext
   929→                    .map(proof => (!hasV1Accounts ? bn(0) : proof.root)) // TODO: find better solution.
   930→                    .concat(newAddressProofs.map(proof => proof.root)),
   931→                rootIndices: merkleProofsWithContext
   932→                    .map(proof => proof.rootIndex)
   933→                    // TODO(crank): make dynamic to enable forester support in
   934→                    // test-rpc.ts. Currently this is a static root because the
   935→                    // address tree doesn't advance.
   936→                    .concat(newAddressProofs.map(_ => 3)),
   937→                leafIndices: merkleProofsWithContext
   938→                    .map(proof => proof.leafIndex)
   939→                    .concat(
   940→                        newAddressProofs.map(proof =>
   941→                            proof.indexHashedIndexedElementLeaf.toNumber(),
   942→                        ),
   943→                    ),
   944→                leaves: merkleProofsWithContext
   945→                    .map(proof => bn(proof.hash))
   946→                    .concat(newAddressProofs.map(proof => bn(proof.value))),
   947→                treeInfos: merkleProofsWithContext
   948→                    .map(proof => proof.treeInfo)
   949→                    .concat(newAddressProofs.map(proof => proof.treeInfo)),
   950→                proveByIndices: merkleProofsWithContext
   951→                    .map(proof => proof.proveByIndex)
   952→                    .concat(newAddressProofs.map(_ => false)),
   953→            };
   954→        } else throw new Error('Invalid input');
   955→
   956→        return validityProof;
   957→    }
