   383→export async function getSolanaArgs({
   384→  additionalPrograms,
   385→  upgradeablePrograms,
   386→  skipSystemAccounts,
   387→  limitLedgerSize,
   388→  rpcPort,
   389→  gossipHost,
   390→  downloadBinaries = true,
   391→  cloneNetwork,
   392→  verbose = false,
   393→  skipReset = false,
   394→}: {
   395→  additionalPrograms?: { address: string; path: string }[];
   396→  upgradeablePrograms?: {
   397→    address: string;
   398→    path: string;
   399→    upgradeAuthority: string;
   400→  }[];
   401→  skipSystemAccounts?: boolean;
   402→  limitLedgerSize?: number;
   403→  rpcPort?: number;
   404→  gossipHost?: string;
   405→  downloadBinaries?: boolean;
   406→  cloneNetwork?: "devnet" | "mainnet";
   407→  verbose?: boolean;
   408→  skipReset?: boolean;
   409→}): Promise<Array<string>> {
   410→  const dirPath = programsDirPath();
   411→
   412→  const solanaArgs = [
   413→    `--limit-ledger-size=${limitLedgerSize}`,
   414→    `--rpc-port=${rpcPort}`,
   415→    `--bind-address=${gossipHost}`,
   416→    "--quiet",
   417→  ];
   418→
   419→  if (!skipReset) {
   420→    solanaArgs.unshift("--reset");
   421→  }
   422→
   423→  // Add cluster URL if cloning from a network
   424→  if (cloneNetwork) {
   425→    const clusterUrl = cloneNetwork === "devnet" ? "devnet" : "mainnet-beta";
   426→    solanaArgs.push("--url", clusterUrl);
   427→  }
   428→
   429→  // Process system programs
   430→  for (const program of SYSTEM_PROGRAMS) {
   431→    const shouldClone = cloneNetwork && PROGRAMS_TO_CLONE.includes(program.id);
   432→
   433→    if (shouldClone) {
   434→      // Clone program from network
   435→      solanaArgs.push("--clone-upgradeable-program", program.id);
   436→    } else {
   437→      // Load program from local binary
   438→      const localFilePath = programFilePath(program.name!);
   439→      if (program.name === "spl_noop.so" || downloadBinaries) {
   440→        await downloadBinIfNotExists({
   441→          localFilePath,
   442→          dirPath,
   443→          owner: "Lightprotocol",
   444→          repoName: "light-protocol",
   445→          remoteFileName: program.name!,
   446→          tag: program.tag,
   447→        });
   448→      }
   449→      solanaArgs.push("--bpf-program", program.id, localFilePath);
   450→    }
   451→  }
   452→
   453→  // Clone all accounts owned by the programs being cloned
   454→  if (cloneNetwork) {
   455→    const rpcUrl =
   456→      cloneNetwork === "devnet"
   457→        ? "https://api.devnet.solana.com"
   458→        : "https://api.mainnet-beta.solana.com";
   459→
   460→    for (const programId of PROGRAMS_TO_CLONE) {
   461→      if (verbose) {
   462→        console.log(`Fetching accounts owned by ${programId}...`);
   463→      }
   464→      const accounts = await getProgramOwnedAccounts(programId, rpcUrl);
   465→      if (verbose) {
   466→        console.log(`Found ${accounts.length} accounts`);
   467→      }
   468→      for (const account of accounts) {
   469→        solanaArgs.push("--maybe-clone", account);
   470→      }
   471→    }
   472→  }
   473→
   474→  // Add additional user-provided programs (always loaded locally)
   475→  if (additionalPrograms) {
   476→    for (const program of additionalPrograms) {
   477→      solanaArgs.push("--bpf-program", program.address, program.path);
   478→    }
   479→  }
   480→
   481→  // Add upgradeable programs (with upgrade authority)
   482→  if (upgradeablePrograms) {
   483→    for (const program of upgradeablePrograms) {
   484→      solanaArgs.push(
   485→        "--upgradeable-program",
   486→        program.address,
   487→        program.path,
   488→        program.upgradeAuthority,
   489→      );
   490→    }
   491→  }
   492→
   493→  // Load local system accounts only if not cloning from network
   494→  if (!skipSystemAccounts && !cloneNetwork) {
   495→    const accountsRelPath = "../../accounts";
   496→    const accountsPath = path.resolve(__dirname, accountsRelPath);
   497→    solanaArgs.push("--account-dir", accountsPath);
   498→  }
   499→
   500→  return solanaArgs;
   501→}
