   589→  return path.join(os.homedir(), ".config", "light", "bin");
   590→}
   591→
   592→function getSurfpoolBinaryPath(): string {
   593→  return path.join(getSurfpoolBinDir(), "surfpool");
   594→}
   595→
   596→function getInstalledSurfpoolVersion(): string | null {
   597→  const binaryPath = getSurfpoolBinaryPath();
   598→
   599→  if (!fs.existsSync(binaryPath)) {
   600→    return null;
   601→  }
   602→
   603→  try {
   604→    const output = execSync(`"${binaryPath}" --version`, {
   605→      encoding: "utf-8",
   606→      timeout: 5000,
   607→    }).trim();
   608→    const match = output.match(/(\d+\.\d+\.\d+)/);
   609→    return match ? match[1] : null;
   610→  } catch {
   611→    return null;
   612→  }
   613→}
   614→
   615→async function downloadSurfpoolBinary(): Promise<void> {
   616→  const binPath = getSurfpoolBinaryPath();
   617→  const dirPath = getSurfpoolBinDir();
   618→  const assetName = getSurfpoolAssetName();
   619→
   620→  if (!fs.existsSync(dirPath)) {
   621→    fs.mkdirSync(dirPath, { recursive: true });
   622→  }
   623→
   624→  // Remove existing binary so downloadBinIfNotExists actually downloads
   625→  if (fs.existsSync(binPath)) {
   626→    fs.unlinkSync(binPath);
   627→  }
   628→
   629→  await downloadBinIfNotExists({
   630→    localFilePath: binPath,
   631→    dirPath,
   632→    owner: "Lightprotocol",
   633→    repoName: "surfpool",
   634→    remoteFileName: assetName,
   635→    tag: SURFPOOL_RELEASE_TAG,
   636→  });
   637→}
   638→
   639→async function ensureSurfpoolBinary(): Promise<string> {
   640→  const binPath = getSurfpoolBinaryPath();
   641→  const installedVersion = getInstalledSurfpoolVersion();
   642→
   643→  if (installedVersion === SURFPOOL_VERSION) {
   644→    return binPath;
   645→  }
   646→
   647→  if (installedVersion) {
   648→    console.log(
   649→      `Surfpool version mismatch. Expected: ${SURFPOOL_VERSION}, Found: ${installedVersion}. Downloading correct version...`,
   650→    );
   651→  } else if (fs.existsSync(binPath)) {
   652→    console.log(
   653→      "Surfpool binary found but version could not be determined. Downloading latest version...",
   654→    );
   655→  }
   656→
   657→  await downloadSurfpoolBinary();
   658→  return binPath;
   659→}
