   661→export async function startTestValidator({
   662→  additionalPrograms,
   663→  upgradeablePrograms,
   664→  skipSystemAccounts,
   665→  limitLedgerSize,
   666→  rpcPort,
   667→  gossipHost,
   668→  validatorArgs,
   669→  geyserConfig,
   670→  cloneNetwork,
   671→  verbose,
   672→  skipReset,
   673→  useSurfpool,
   674→  additionalAccountDirs,
   675→}: {
   676→  additionalPrograms?: { address: string; path: string }[];
   677→  upgradeablePrograms?: {
   678→    address: string;
   679→    path: string;
   680→    upgradeAuthority: string;
   681→  }[];
   682→  skipSystemAccounts?: boolean;
   683→  limitLedgerSize?: number;
   684→  rpcPort?: number;
   685→  gossipHost?: string;
   686→  validatorArgs?: string;
   687→  geyserConfig?: string;
   688→  cloneNetwork?: "devnet" | "mainnet";
   689→  verbose?: boolean;
   690→  skipReset?: boolean;
   691→  useSurfpool?: boolean;
   692→  additionalAccountDirs?: string[];
   693→}) {
   694→  if (useSurfpool) {
   695→    const command = await ensureSurfpoolBinary();
   696→    const surfpoolArgs = await getSurfpoolArgs({
   697→      additionalPrograms,
   698→      upgradeablePrograms,
   699→      skipSystemAccounts,
   700→      rpcPort,
   701→      gossipHost,
   702→      additionalAccountDirs,
   703→    });
   704→
   705→    await killTestValidator(rpcPort);
   706→    await new Promise((r) => setTimeout(r, 1000));
   707→
   708→    console.log("Starting surfpool...");
   709→    spawnBinary(command, surfpoolArgs, process.env);
   710→  } else {
   711→    const command = "solana-test-validator";
   712→    const solanaArgs = await getSolanaArgs({
   713→      additionalPrograms,
   714→      upgradeablePrograms,
   715→      skipSystemAccounts,
   716→      limitLedgerSize,
   717→      rpcPort,
   718→      gossipHost,
   719→      cloneNetwork,
   720→      verbose,
   721→      skipReset,
   722→    });
   723→
   724→    await killTestValidator(rpcPort);
   725→
   726→    await new Promise((r) => setTimeout(r, 1000));
   727→
   728→    // Add geyser config if provided
   729→    if (geyserConfig) {
   730→      solanaArgs.push("--geyser-plugin-config", geyserConfig);
   731→    }
   732→
   733→    // Add custom validator args last
   734→    if (validatorArgs) {
   735→      solanaArgs.push(...validatorArgs.split(" "));
   736→    }
   737→    console.log("Starting test validator...");
   738→    // Use spawnBinary instead of executeCommand to properly detach the process.
   739→    // This ensures the validator survives when the CLI exits (executeCommand uses
   740→    // piped stdio which causes SIGPIPE when parent exits).
   741→    // Pass process.env directly to maintain same env behavior as before.
   742→    spawnBinary(command, solanaArgs, process.env);
   743→  }
   744→}
   745→
   746→export async function killTestValidator(rpcPort: number = 8899) {
   747→  await killProcess("solana-test-validator");
   748→  await killProcess("surfpool");
   749→
   750→  // Fallback: kill anything still listening on the RPC port.
   751→  // find-process name matching can miss processes depending on platform
   752→  // and how the binary path appears in the process table.
   753→  try {
   754→    await killProcessByPort(rpcPort);
   755→  } catch {
   756→    // No process listening on the port, nothing to do.
   757→  }
   758→}
