   106→    println!("Using RPC: {}", rpc_url);
   107→    let client = RpcClient::new(rpc_url);
   108→
   109→    for pubkey_str in &opts.pubkeys {
   110→        let pubkey = Pubkey::from_str(pubkey_str)?;
   111→
   112→        if opts.lut {
   113→            fetch_and_process_lut(&client, &pubkey, &opts.add_pubkeys)?;
   114→        } else {
   115→            fetch_and_save_account(&client, &pubkey)?;
   116→        }
   117→    }
   118→
   119→    println!("Processed {} accounts", opts.pubkeys.len());
   120→    Ok(())
   121→}
