   123→fn network_to_url(network: &str) -> String {
   124→    match network {
   125→        "mainnet" => "https://api.mainnet-beta.solana.com".to_string(),
   126→        "devnet" => "https://api.devnet.solana.com".to_string(),
   127→        "testnet" => "https://api.testnet.solana.com".to_string(),
   128→        "local" | "localnet" => "http://localhost:8899".to_string(),
   129→        custom => custom.to_string(),
   130→    }
