   133→fn fetch_and_save_account(client: &RpcClient, pubkey: &Pubkey) -> anyhow::Result<()> {
   134→    let account = client
   135→        .get_account(pubkey)
   136→        .context(format!("Failed to fetch account {}", pubkey))?;
   137→
   138→    let filename = format!("account_{}.json", pubkey);
   139→    write_account_json(&account, pubkey, &filename)?;
   140→
   141→    println!(
   142→        "Saved {} ({} bytes, {} lamports)",
   143→        filename,
   144→        account.data.len(),
   145→        account.lamports
   146→    );
   147→    Ok(())
   148→}
   149→
   150→fn fetch_and_process_lut(
   151→    client: &RpcClient,
   152→    pubkey: &Pubkey,
   153→    add_pubkeys: &Option<String>,
   154→) -> anyhow::Result<()> {
   155→    println!("Fetching lookup table: {}", pubkey);
   156→
   157→    let account = client
   158→        .get_account(pubkey)
   159→        .context(format!("Failed to fetch LUT {}", pubkey))?;
   160→
   161→    let modified_data = decode_and_modify_lut(&account.data, add_pubkeys)?;
   162→    let filename = format!("modified_lut_{}.json", pubkey);
   163→
   164→    let data_base64 = base64::encode(&modified_data);
   165→    let json_obj = json!({
   166→        "pubkey": pubkey.to_string(),
   167→        "account": {
   168→            "lamports": account.lamports,
   169→            "data": [data_base64, "base64"],
   170→            "owner": account.owner.to_string(),
   171→            "executable": account.executable,
   172→            "rentEpoch": account.rent_epoch,
   173→            "space": modified_data.len(),
   174→        }
   175→    });
   176→
   177→    let mut file = File::create(&filename)?;
   178→    file.write_all(json_obj.to_string().as_bytes())?;
   179→
   180→    println!("Saved LUT {} with last_extended_slot set to 0", filename);
   181→    Ok(())
   182→}
   183→
   184→fn decode_and_modify_lut(data: &[u8], add_pubkeys: &Option<String>) -> anyhow::Result<Vec<u8>> {
   185→    if data.len() < 56 {
   186→        anyhow::bail!("LUT data too small");
   187→    }
   188→
   189→    let discriminator = u32::from_le_bytes([data[0], data[1], data[2], data[3]]);
   190→    if discriminator != 1 {
   191→        anyhow::bail!(
   192→            "Not a lookup table account (discriminator: {})",
   193→            discriminator
   194→        );
   195→    }
   196→
   197→    let mut modified_data = data.to_vec();
   198→
   199→    let current_last_extended_slot = u64::from_le_bytes([
   200→        data[12], data[13], data[14], data[15], data[16], data[17], data[18], data[19],
   201→    ]);
   202→    modified_data[12..20].copy_from_slice(&0u64.to_le_bytes());
   203→
   204→    let addresses_start = 56;
   205→    let mut num_addresses = (data.len().saturating_sub(addresses_start)) / 32;
   206→
   207→    println!("  Number of addresses: {}", num_addresses);
   208→    println!(
   209→        "  Modified last_extended_slot: {} -> 0",
   210→        current_last_extended_slot
   211→    );
   212→
   213→    if let Some(pubkeys_str) = add_pubkeys {
   214→        for pubkey_str in pubkeys_str
   215→            .split(',')
   216→            .map(|s| s.trim())
   217→            .filter(|s| !s.is_empty())
   218→        {
   219→            let add_pubkey = Pubkey::from_str(pubkey_str)?;
   220→
   221→            let mut exists = false;
   222→            for i in 0..num_addresses {
   223→                let start = addresses_start + (i * 32);
   224→                let end = start + 32;
   225→                if end <= modified_data.len() {
   226→                    let existing = Pubkey::try_from(&modified_data[start..end])?;
   227→                    if existing == add_pubkey {
   228→                        println!("  Pubkey {} already exists at index {}", add_pubkey, i);
   229→                        exists = true;
   230→                        break;
   231→                    }
   232→                }
   233→            }
   234→
   235→            if !exists {
   236→                modified_data.extend_from_slice(&add_pubkey.to_bytes());
   237→                println!("  Added pubkey: {} at index {}", add_pubkey, num_addresses);
   238→                num_addresses += 1;
   239→            }
   240→        }
   241→    }
   242→
   243→    Ok(modified_data)
   244→}
   245→
   246→fn write_account_json(account: &Account, pubkey: &Pubkey, filename: &str) -> anyhow::Result<()> {
   247→    let data_base64 = base64::encode(&account.data);
   248→    let json_obj = json!({
   249→        "pubkey": pubkey.to_string(),
   250→        "account": {
   251→            "lamports": account.lamports,
   252→            "data": [data_base64, "base64"],
   253→            "owner": account.owner.to_string(),
   254→            "executable": account.executable,
   255→            "rentEpoch": account.rent_epoch,
   256→            "space": account.data.len(),
   257→        }
   258→    });
   259→
   260→    let mut file = File::create(filename)?;
   261→    file.write_all(json_obj.to_string().as_bytes())?;
   262→    Ok(())
   263→}
